def constant_time(lst):
    return lst[0]

def linear_time(lst):
    total = 0
    for x in lst:
        total += x
    return total

def quadratic_time(lst):
    count = 0
    for i in range(len(lst)):
        for j in range(len(lst)):
            count += 1
    return count

data = [1, 2, 3, 4, 5]
print(constant_time(data))
print(linear_time(data))
print(quadratic_time(data))
